	(87, 1, '2026-03-26 14:33:53', '2026-03-26 13:32:47', ' ', '', '', 'publish', 'closed', 'closed', '', '87', '', '', '2026-03-26 14:33:53', '2026-03-26 13:33:53', '', 0, 'http://localhost:8080/?p=87', 5, 'nav_menu_item', '', 0),
